import { makeStyles } from '@material-ui/core'
import React from 'react'
import Login from '../pages/Login'

const useStyle = makeStyles({
  center: {
    position: 'fixed',
    width: '100%',
    height: '100%'
  }
})

export default function Center() {
  const classes = useStyle();

  return (
    <div className={classes.center}>

        <Login />
    </div>
  )
}
